    }

    const N_A = Math.floor(N / 2);
    const A = nums.slice(0, N_A);
    const B = nums.slice(N_A);
    const N_B = N - N_A;

    // mapA: stores {XOR_sum: max_size} for subsets of A
    // Initialize with the empty set: XOR sum 0, size 0.
    const mapA = new Map();
    mapA.set(0, 0);

    // 1. Process A (First half)
    for (let i = 1; i < (1 << N_A); i++) {
        let currentXor = 0;
        let currentSize = 0;
        for (let k = 0; k < N_A; k++) {
            if ((i >> k) & 1) {
                currentXor ^= A[k];
                currentSize++;
            }
        }

        // Update mapA: keep the maximum size for this XOR sum
        if (!mapA.has(currentXor) || mapA.get(currentXor) < currentSize) {
            mapA.set(currentXor, currentSize);
        }
    }

    // Initialize max_size to -1, indicating no solution found yet.
    // We must be able to handle the case where target=0 and only the empty set works (size 0).
    let maxSize = -1;

    // Check if target itself is achievable by A alone (covers case where B is empty subset, size 0)
    if (mapA.has(target)) {
        maxSize = Math.max(maxSize, mapA.get(target));
    }


    // 2. Process B (Second half)
    // Iterate through all 2^N_B subsets of B
    for (let j = 0; j < (1 << N_B); j++) {
        let currentXorB = 0;
        let currentSizeB = 0;
        for (let k = 0; k < N_B; k++) {
            if ((j >> k) & 1) {
                currentXorB ^= B[k];
                currentSizeB++;
            }
        }

        // Required XOR sum from A: X_A_req = target XOR X_B
        const requiredXorA = target ^ currentXorB;

        if (mapA.has(requiredXorA)) {
            const sizeA = mapA.get(requiredXorA);
            const totalSize = sizeA + currentSizeB;

            if (totalSize > maxSize) {
                maxSize = totalSize;
            }
