 * @param nums The input array of numbers.
 * @param target The required XOR sum.
 * @return The minimum number of removals, or -1 if impossible.
 */
def solve(nums: Array[Long], target: Long): Long = {
    val N = nums.length

    if (N == 0) {
        return if (target == 0) 0 else -1
    }

    val NA = N / 2
    val A = nums.take(NA).toArray
    val B = nums.drop(NA).toArray
    val NB = N - NA

    // mapA: stores {XOR_sum: max_size} for subsets of A
    // Size is tracked using Int since N <= 40.
    val mapA: MutableMap[Long, Int] = mutable.Map()
    // Initialize with the empty set: XOR sum 0, size 0.
    mapA.put(0L, 0)

    // 1. Process A (First half)
    val maxMaskA = 1 << NA
    for (i <- 1 until maxMaskA) {
        var currentXor: Long = 0
        var currentSize: Int = 0
        for (k <- 0 until NA) {
            if ((i >> k) & 1 != 0) {
