        if (currentSize > currentMaxSize) {
            mapA.put(currentXor, currentSize)
        }
    }

    // Initialize maxSize to -1, indicating no solution found yet.
    var maxSize: Int = -1

    // Check if target itself is achievable by A alone (covers case where B is empty subset, size 0)
    mapA.get(target).foreach { size =>
        maxSize = Math.max(maxSize, size)
    }

    // 2. Process B (Second half)
    val maxMaskB = 1 << NB
    for (j <- 0 until maxMaskB) {
        var currentXorB: Long = 0
        var currentSizeB: Int = 0
