        val requiredXorA: Long = target ^ currentXorB

        mapA.get(requiredXorA).foreach { sizeA =>
            val totalSize = sizeA + currentSizeB
            if (totalSize > maxSize) {
                maxSize = totalSize
            }
        }
    }

    if (maxSize == -1) {
        -1L
    } else {
        // The minimum number of removals is N - maximum size of the remaining set.
        (N - maxSize).toLong
